module sr_flip_flop (
    input wire S,
    input wire R,
    input wire clk,
    output reg obf_Q
);
    always @(posedge clk) begin
        if (S && !R) 
            obf_Q <= 1; // Set
        else if (!S && R) 
            obf_Q <= 0; // Reset
        // If S and R are both 0, obf_Q remains unchanged
    end
endmodule
